def predict_next_frame(grid):
    new_grid = [[0 for _ in range(len(grid[0]))] for _ in range(len(grid))]
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            if grid[i][j] == 1:
                # Rule: A cell with 1 becomes 0 if surrounded by 4 or more 1s
                count = sum(grid[i + di][j + dj] for di in (-1, 0, 1) for dj in (-1, 0, 1) if 0 <= i + di < len(grid) and 0 <= j + dj < len(grid))
                if count >= 4:
                    new_grid[i][j] = 0
                else:
                    new_grid[i][j] = 1
            else:
                # Rule: A cell with 0 becomes 1 if surrounded by exactly 3 1s
                count = sum(grid[i + di][j + dj] for di in (-1, 0, 1) for dj in (-1, 0, 1) if 0 <= i + di < len(grid) and 0 <= j + dj < len(grid))
                if count == 3:
                    new_grid[i][j] = 1
                else:
                    new_grid[i][j] = 0
    return new_grid

